{"tool_call_id": "toolu_01LChJzmt7ttoxdrkY3ZJLLs", "name": "ToolTextFileEdit", "args": {"short_description": "Add priceHistory to store.ts", "filename": "src/store.ts", "new_text": "import { create } from 'zustand';

interface SimulationState {
  balance: number;
  isRunning: boolean;
  currentPrice: number;
  priceHistory: number[];
  toggleSimulation: () => void;
  tick: () => void;
}

export const useSimulationStore = create<SimulationState>((set) => ({
  balance: 10000,
  isRunning: false,
  currentPrice: 150,
  priceHistory: [150],

  toggleSimulation: () =>
    set((state) => ({ isRunning: !state.isRunning })),

  tick: () =>
    set((state) => {
      // Random walk: ±0.5% per tick
      const change = state.currentPrice * (Math.random() * 0.01 - 0.005);
      const newPrice = Math.max(1, state.currentPrice + change);
      // Simulate P&L: small random balance drift
      const pnl = (Math.random() - 0.495) * 10;
      return {
        currentPrice: parseFloat(newPrice.toFixed(2)),
        balance: parseFloat((state.balance + pnl).toFixed(2)),
        priceHistory: [...state.priceHistory, newPrice].slice(-100),
      };
    }),
}));
