{"tool_call_id": "toolu_01UPxaqL82LUWWbLZ3hFtcDi", "name": "ToolTextFileEdit", "args": {"short_description": "Rewrite store.ts with nodes/connections/logs + trading logic", "filename": "src/store.ts", "new_text": "import { create } from 'zustand';

export interface StrategyNode {
  id: string;
  type: 'CONDITION' | 'ACTION';
  x: number;
  y: number;
  data: {
    label: string;
    // CONDITION: targetPrice, operator ('lt' | 'gt')
    targetPrice?: number;
    operator?: 'lt' | 'gt';
    // ACTION: side ('BUY' | 'SELL'), amount
    side?: 'BUY' | 'SELL';
    amount?: number;
  };
}

export interface Connection {
  fromId: string;
  toId: string;
}

export interface TradeLog {
  id: string;
  message: string;
  time: string;
  type: 'BUY' | 'SELL';
}

interface SimulationState {
  balance: number;
  isRunning: boolean;
  currentPrice: number;
  priceHistory: number[];
  nodes: StrategyNode[];
  connections: Connection[];
  logs: TradeLog[];

  toggleSimulation: () => void;
  tick: () => void;
  addNode: (node: StrategyNode) => void;
  updateNodePosition: (id: string, x: number, y: number) => void;
  updateNodeData: (id: string, data: Partial<StrategyNode['data']>) => void;
  connectNodes: (fromId: string, toId: string) => void;
  removeConnection: (fromId: string, toId: string) => void;
}

export const useSimulationStore = create<SimulationState>((set, get) => ({
  balance: 10000,
  isRunning: false,
  currentPrice: 150,
  priceHistory: [150],
  nodes: [],
  connections: [],
  logs: [],

  toggleSimulation: () =>
    set((state) => ({ isRunning: !state.isRunning })),

  tick: () =>
    set((state) => {
      // Random walk: ±0.5% per tick
      const change = state.currentPrice * (Math.random() * 0.01 - 0.005);
      const newPrice = Math.max(1, state.currentPrice + change);
      const price = parseFloat(newPrice.toFixed(2));

      // Evaluate CONDITION -> ACTION connections
      let newBalance = state.balance;
      const firedConnections: string[] = []; // keys "fromId:toId" to remove
      const newLogs: TradeLog[] = [];

      for (const conn of state.connections) {
        const condNode = state.nodes.find(
          (n) => n.id === conn.fromId && n.type === 'CONDITION'
        );
        const actNode = state.nodes.find(
          (n) => n.id === conn.toId && n.type === 'ACTION'
        );
        if (!condNode || !actNode) continue;

        const { operator, targetPrice } = condNode.data;
        const { side, amount } = actNode.data;
        if (targetPrice == null || !operator || !side || !amount) continue;

        // Evaluate condition against new price
        const condMet =
          operator === 'lt' ? price < targetPrice : price > targetPrice;

        if (condMet) {
          const cost = side === 'BUY' ? -amount : amount;
          newBalance = parseFloat((newBalance + cost).toFixed(2));
          firedConnections.push(`${conn.fromId}:${conn.toId}`);

          const now = new Date();
