// ─── SVG Connection Lines ─────────────────────────────────────────────────────

function ConnectionLines() {
  const { nodes, connections } = useSimulationStore();

  return (
    <svg
      className="absolute inset-0 w-full h-full pointer-events-none"
      style={{ zIndex: 5 }}
    >
      <defs>
        <filter id="glow">
          <feGaussianBlur stdDeviation="3" result="coloredBlur" />
          <feMerge>
            <feMergeNode in="coloredBlur" />
            <feMergeNode in="SourceGraphic" />
          </feMerge>
        </filter>
      </defs>
      {connections.map((conn) => {
        const from = nodes.find((n) => n.id === conn.fromId);
        const to = nodes.find((n) => n.id === conn.toId);
        if (!from || !to) return null;

        // Connect from right-center of from node to left-center of to node
        const NODE_W = 200;
        const NODE_H = 90;
        const x1 = from.x + NODE_W;
        const y1 = from.y + NODE_H / 2;
        const x2 = to.x;
        const y2 = to.y + NODE_H / 2;
        const cx = (x1 + x2) / 2;

        return (
          <g key={`${conn.fromId}-${conn.toId}`}>
            {/* Glow layer */}
            <path
              d={`M ${x1} ${y1} C ${cx} ${y1}, ${cx} ${y2}, ${x2} ${y2}`}
              fill="none"
              stroke="rgba(167,139,250,0.4)"
              strokeWidth="4"
              filter="url(#glow)"
            />
            {/* Core line */}
            <path
              d={`M ${x1} ${y1} C ${cx} ${y1}, ${cx} ${y2}, ${x2} ${y2}`}
              fill="none"
              stroke="#a78bfa"
              strokeWidth="1.5"
              strokeDasharray="6 3"
            />
            {/* Arrow tip */}
            <circle cx={x2} cy={y2} r="3" fill="#a78bfa" />
          </g>
        );
      })}
    </svg>
  );
}

// ─── Sidebar ──────────────────────────────────────────────────────────────────

export default function Sidebar() {
  const { nodes, logs, addNode, connectNodes } = useSimulationStore();
  const canvasRef = useRef<HTMLDivElement>(null);

  // Track which condition node is in "connecting" mode
  const [pendingFrom, setPendingFrom] = useState<string | null>(null);

  function spawnNode(type: 'CONDITION' | 'ACTION') {
    const id = `${type}-${Date.now()}`;
    const offset = nodes.length * 20;
    const node: StrategyNode = {
      id,
      type,
      x: type === 'CONDITION' ? 16 + offset : 230 + offset,
      y: 40 + offset,
      data:
        type === 'CONDITION'
          ? { label: 'Condition', operator: 'lt', targetPrice: 148 }
          : { label: 'Action', side: 'BUY', amount: 500 },
    };
    addNode(node);
  }

  // Handle ACTION target clicks bubbled from NodeCard
  function handleCanvasClick(e: React.MouseEvent) {
    const target = e.target as HTMLElement;
    const customEv = (e.nativeEvent as unknown as CustomEvent<string>);
    if (customEv.type === 'node-target-click' && pendingFrom) {
      connectNodes(pendingFrom, customEv.detail);
      setPendingFrom(null);
    }
  }

  return (
    <aside className="w-96 flex flex-col p-4 gap-3 shrink-0">

      {/* ── Node Editor ── */}
      <div className="flex-1 bg-[#161b22]/80 backdrop-blur-md border border-white/10 rounded-xl flex flex-col overflow-hidden min-h-0">

        {/* Header + spawn buttons */}
        <div className="px-4 pt-4 pb-3 border-b border-white/10 shrink-0">
          <p className="text-[10px] text-white/40 uppercase tracking-widest font-semibold mb-3">
            Node Strategy Builder
          </p>
          <div className="flex gap-2">
            <button
              onClick={() => spawnNode('CONDITION')}
              className="flex-1 text-xs py-1.5 rounded-lg border border-violet-500/50 text-violet-400 hover:bg-violet-500/10 transition-all font-semibold tracking-wide"
            >
              + Condition
            </button>
            <button
              onClick={() => spawnNode('ACTION')}
              className="flex-1 text-xs py-1.5 rounded-lg border border-[#00ff88]/40 text-[#00ff88] hover:bg-[#00ff88]/10 transition-all font-semibold tracking-wide"
            >
              + Action
            </button>
          </div>
        </div>

        {/* Node canvas */}
        <div
          ref={canvasRef}
          className="flex-1 relative overflow-hidden"
          style={{
            backgroundImage:
              'radial-gradient(circle, rgba(255,255,255,0.04) 1px, transparent 1px)',
            backgroundSize: '24px 24px',
          }}
          onClick={handleCanvasClick}
          onClickCapture={(e) => {
            // Handle bubbled custom events
            const nativeEv = e.nativeEvent as unknown as CustomEvent<string>;
            if (nativeEv.type === 'node-target-click' && pendingFrom) {
              connectNodes(pendingFrom, nativeEv.detail);
              setPendingFrom(null);
            }
          }}
        >
          <ConnectionLines />

          {nodes.length === 0 && (
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
              <p className="text-white/15 text-xs tracking-widest uppercase text-center leading-relaxed">
                Spawn nodes above<br />drag to arrange<br />connect condition → action
              </p>
            </div>
          )}

          {nodes.map((node) => (
            <NodeCard key={node.id} node={node} />
          ))}
        </div>
      </div>

      {/* ── Strategy Log ── */}
      <div
        className="bg-[#161b22]/80 backdrop-blur-md border border-white/10 rounded-xl p-4 shrink-0"
        style={{ maxHeight: 200 }}
      >
        <p className="text-[10px] text-white/40 uppercase tracking-widest font-semibold border-b border-white/10 pb-2 mb-2">
          Strategy Log
        </p>
        <div className="overflow-y-auto space-y-1" style={{ maxHeight: 140 }}>
          {logs.length === 0 ? (
            <p className="text-white/20 text-xs font-mono tracking-widest">
              No trades yet…
            </p>
          ) : (
            logs.map((log) => (
              <div key={log.id} className="flex items-center gap-2">
                <span
                  className={`font-mono text-xs font-bold ${
                    log.type === 'BUY' ? 'text-[#00ff88]' : 'text-[#ff4d4d]'
                  }`}
                  style={{
                    textShadow:
                      log.type === 'BUY'
                        ? '0 0 8px rgba(0,255,136,0.7)'
                        : '0 0 8px rgba(255,77,77,0.7)',
                  }}
                >
                  {log.type}
                </span>
                <span className="font-mono text-xs text-white/60 flex-1">
                  {log.message}
                </span>
                <span className="font-mono text-[10px] text-white/25">{log.time}</span>
              </div>
            ))
          )}
        </div>
      </div>
    </aside>
  );
}
